import { readFileSync, writeFileSync } from "node:fs";
// eslint-disable-next-line n/no-unsupported-features/node-builtins
import { findPackageJSON } from "node:module";
import type { ParseError } from "jsonc-parser";
import { findNodeAtLocation, getNodeValue, parseTree } from "jsonc-parser";
import type {
  DependencyValue,
  PackageJson,
  ParsedPackageJson,
} from "./packageTypes.ts";

if (typeof findPackageJSON !== "function") {
  // eslint-disable-next-line unicorn/prefer-type-error
  throw new Error("check-package-dependencies requires node >= 22.14.0");
}

export function readPkgJson(packagePath: string): PackageJson {
  return JSON.parse(readFileSync(packagePath, "utf8")) as PackageJson;
}

export function stringifyPkgJson(pkg: PackageJson): string {
  return `${JSON.stringify(pkg, null, 2)}\n`;
}

export function writePkgJson(packagePath: string, pkg: PackageJson): void {
  writeFileSync(packagePath, stringifyPkgJson(pkg));
}

function getLocationFromOffset(
  packageContent: string,
  offset: number,
): { line: number; column: number } {
  if (offset < 0 || offset > packageContent.length) {
    throw new Error(
      `Offset ${offset} is out of bounds (0 to ${packageContent.length})`,
    );
  }

  const lines = packageContent.slice(0, offset).split("\n");
  const lastLine = lines.at(-1);
  return { line: lines.length, column: lastLine ? lastLine.length + 1 : 1 };
}

function validateJsonParsing(
  json: ReturnType<typeof parseTree>,
  errors: ParseError[],
  packagePath: string,
): asserts json is NonNullable<typeof json> {
  if (errors.length > 0) {
    throw new Error(
      `Failed to parse JSON at ${packagePath}: ${errors.map(String).join(", ")}`,
    );
  }
  if (!json) {
    throw new Error(`Failed to parse JSON at ${packagePath}: empty JSON`);
  }
}

function validatePackageName(
  nameNode: ReturnType<typeof findNodeAtLocation>,
  packagePath: string,
): asserts nameNode is NonNullable<typeof nameNode> {
  if (!nameNode) {
    throw new Error(`Invalid package.json at ${packagePath}: no "name" field`);
  }
  if (typeof nameNode.value !== "string") {
    throw new TypeError(
      `Invalid package.json at ${packagePath}: "name" field is not a string`,
    );
  }
}

const dependencyFieldNames = [
  "dependencies",
  "devDependencies",
  "peerDependencies",
  "resolutions",
  "resolutionsExplained",
] as const;

function parseDependencyField(
  json: NonNullable<ReturnType<typeof parseTree>>,
  fieldName: (typeof dependencyFieldNames)[number],
  packageContent: string,
  packageValue: PackageJson,
): [string, Record<string, DependencyValue> | undefined] {
  const fieldNode = findNodeAtLocation(json, [fieldName]);
  if (!fieldNode?.children) {
    return [fieldName, undefined];
  }

  const dependencies = Object.fromEntries<DependencyValue>(
    fieldNode.children
      .filter((child) => child.type === "property")
      .map((propertyNode) => {
        const nameNode = propertyNode.children![0]!;
        const valueNode = propertyNode.children![1]!;

        const name = getNodeValue(nameNode) as string;
        const value = getNodeValue(valueNode) as string;
        const startLocation = getLocationFromOffset(
          packageContent,
          propertyNode.offset,
        );
        const valueStartLocation = getLocationFromOffset(
          packageContent,
          valueNode.offset,
        );

        const parsedDependency: DependencyValue = {
          fieldName,
          name,
          value,
          locations: {
            all: {
              start: startLocation,
              end: {
                line: startLocation.line,
                column: startLocation.column + propertyNode.length,
              },
            },
            name: {
              start: startLocation,
              end: {
                line: startLocation.line,
                column: startLocation.column + nameNode.length,
              },
            },
            value: {
              start: valueStartLocation,
              end: {
                line: valueStartLocation.line,
                column: valueStartLocation.column + valueNode.length,
              },
            },
          },
          ranges: {
            all: [propertyNode.offset, valueNode.offset + valueNode.length],
            name: [propertyNode.offset, nameNode.offset + nameNode.length],
            value: [valueNode.offset, valueNode.offset + valueNode.length],
          },
          changeValue(newValue: string) {
            packageValue[fieldName]![name] = newValue;
            parsedDependency.value = newValue;
          },
          toString() {
            return `${JSON.stringify(parsedDependency.name)}: ${JSON.stringify(parsedDependency.value)}`;
          },
        };

        return [name, parsedDependency];
      }),
  );

  return [fieldName, dependencies];
}

export function parsePkg(
  packageContent: string,
  packagePath: string,
): ParsedPackageJson {
  const errors: ParseError[] = [];
  const json = parseTree(packageContent, errors, { disallowComments: true });
  validateJsonParsing(json, errors, packagePath);

  const nameNode = findNodeAtLocation(json, ["name"]);
  validatePackageName(nameNode, packagePath);

  const value = getNodeValue(json) as PackageJson;

  return {
    name: getNodeValue(nameNode) as string,
    path: packagePath,
    value,
    ...Object.fromEntries(
      dependencyFieldNames.map((fieldName) =>
        parseDependencyField(json, fieldName, packageContent, value),
      ),
    ),
    change(type, dependencyName, newValue) {
      const dependency = this[type]?.[dependencyName];
      if (dependency) {
        dependency.changeValue(newValue);
      } else {
        value[type] = { ...value[type], [dependencyName]: newValue };
      }
    },
  };
}

// mainly for testing
export function parsePkgValue(
  pkg: unknown,
  packagePath = "unknown_path",
): ParsedPackageJson {
  return parsePkg(JSON.stringify(pkg), packagePath);
}

export function readAndParsePkgJson(packagePath: string): ParsedPackageJson {
  return parsePkg(readFileSync(packagePath, "utf8"), packagePath);
}

/** @internal */
export function internalLoadPackageJsonFromNodeModules(
  pkgDepName: string,
  pkgDirname: string,
): [path: string, pkg: PackageJson] {
  const packagePath = findPackageJSON(
    pkgDepName,
    `file://${pkgDirname}/package.json`,
  );
  if (!packagePath) {
    throw new Error(`Package ${pkgDepName} not found in ${pkgDirname}`);
  }
  return [packagePath, readPkgJson(packagePath)];
}
import type { PackageJson } from "./packageTypes.ts";
import {
  internalLoadPackageJsonFromNodeModules,
  readPkgJson,
} from "./pkgJsonUtils.ts";

type DependencyPackageJsonResult = [pkg: PackageJson, pkgPath: string];

export type GetDependencyPackageJson = (
  pkgDepName: string,
) => DependencyPackageJsonResult;

type NodeModulesPackagePathCache = Map<string, DependencyPackageJsonResult>;

interface CreateGetDependencyPackageJsonOptions {
  pkgDirname: string;
  nodeModulesPackagePathCache?: NodeModulesPackagePathCache;
  /** @internal */
  internalCustomLoadPackageJsonFromNodeModules?: typeof internalLoadPackageJsonFromNodeModules;
  /** @internal */
  internalReadPkgJson?: typeof readPkgJson;
}

export function createGetDependencyPackageJson({
  pkgDirname,
  nodeModulesPackagePathCache = new Map<string, DependencyPackageJsonResult>(),
  internalCustomLoadPackageJsonFromNodeModules = internalLoadPackageJsonFromNodeModules,
  internalReadPkgJson = readPkgJson,
}: CreateGetDependencyPackageJsonOptions): GetDependencyPackageJson {
  return (pkgDepName) => {
    const existing = nodeModulesPackagePathCache.get(pkgDepName);
    if (existing) return existing;
    let pkg: PackageJson;
    let packagePath: string;
    if (pkgDepName.startsWith(".")) {
      packagePath = `${pkgDirname}/${pkgDepName}/package.json`;
      pkg = internalReadPkgJson(packagePath);
    } else {
      try {
        [packagePath, pkg] = internalCustomLoadPackageJsonFromNodeModules(
          pkgDepName,
          pkgDirname,
        );
      } catch (error: unknown) {
        if (!(error instanceof Error)) throw error;

        if (
          (error as NodeJS.ErrnoException).code !==
          "ERR_PACKAGE_PATH_NOT_EXPORTED"
        ) {
          throw error;
        }

        const match = / in (.*[/\\]package\.json)\s+imported from/.exec(
          error.message,
        );

        if (match) {
          const [, matchPackageJson] = match;
          if (!matchPackageJson) throw error;
          packagePath = matchPackageJson;
          pkg = internalReadPkgJson(matchPackageJson);
        } else {
          throw error;
        }
      }
    }
    nodeModulesPackagePathCache.set(pkgDepName, [pkg, packagePath]);
    return [pkg, packagePath];
  };
}
import { TextSourceCodeBase, VisitNodeStep } from "@eslint/plugin-kit";
import type { Location } from "../utils/packageTypes.ts";
import { stringifyPkgJson } from "../utils/pkgJsonUtils.ts";
import type { DependencyValueAst, PackageJsonAst } from "./language.ts";

export class PackageJsonSourceCode extends TextSourceCodeBase {
  declare text: string;
  declare ast: PackageJsonAst;

  constructor({ text, ast }: { text: string; ast: PackageJsonAst }) {
    super({ text, ast });
  }

  override getParent(node: object): object | undefined {
    return undefined;
  }

  override getAncestors(node: object): object[] {
    return [];
  }

  override traverse(): Iterable<VisitNodeStep> {
    return [
      new VisitNodeStep({
        target: this.ast,
        phase: 1,
        args: [this.ast],
      }),
      ...this.ast.children.flatMap((child) => [
        new VisitNodeStep({
          target: child,
          phase: 1,
          args: [child],
        }),
        new VisitNodeStep({
          target: child,
          phase: 2,
          args: [child],
        }),
      ]),
      new VisitNodeStep({
        target: this.ast,
        phase: 2,
        args: [this.ast],
      }),
    ];
  }

  override getText(node: object): string {
    if ("type" in node) {
      if (node.type === "Package") {
        return stringifyPkgJson(this.ast.parsedPkgJson.value);
      }
    }
    throw new Error("Invalid node");
  }

  override getLoc(node: object): Location {
    if ("type" in node) {
      if (node.type === "Package") {
        return { start: { line: 1, column: 1 }, end: { line: 1, column: 1 } };
      }
      if (node.type === "DependencyValue") {
        const dependencyValueAst = node as DependencyValueAst;
        const loc = dependencyValueAst.dependencyValue?.locations.all;
        if (!loc) throw new Error("Invalid node");
        return loc;
      }
    }
    throw new Error("Invalid node");
  }
}
import { dirname } from "node:path";
import type {
  File,
  Language,
  LanguageContext,
  LanguageOptions,
  OkParseResult,
  ParseResult,
} from "@eslint/core";
import type { GetDependencyPackageJson } from "../utils/createGetDependencyPackageJson.ts";
import { createGetDependencyPackageJson } from "../utils/createGetDependencyPackageJson.ts";
import type {
  DependencyTypes,
  DependencyValue,
  ParsedPackageJson,
} from "../utils/packageTypes.ts";
import { parsePkg } from "../utils/pkgJsonUtils.ts";
import { PackageJsonSourceCode } from "./source-code.ts";

export interface PackageJsonAst {
  type: "Package";
  parsedPkgJson: ParsedPackageJson;
  getDependencyPackageJson: GetDependencyPackageJson;
  loc: { line: number; column: number };
  range: [number, number];
  children: DependencyValueAst[];
  value: string;
}

export interface DependencyValueAst {
  type: "DependencyValue";
  dependencyType: DependencyTypes;
  parsedPkgJson: ParsedPackageJson;
  getDependencyPackageJson: GetDependencyPackageJson;
  dependencyValue: DependencyValue | undefined;
  loc: { line: number; column: number };
  range: [number, number];
  value: string;
}

export const PackageJSONLanguage: Language = {
  fileType: "text",
  lineStart: 1,
  columnStart: 1,
  nodeTypeKey: "type",
  visitorKeys: {
    Package: ["DependencyValue"],
    DependencyValue: [],
  },

  validateLanguageOptions(languageOptions: LanguageOptions): void {},

  parse(
    file: File,
    context: LanguageContext<LanguageOptions>,
  ): ParseResult<PackageJsonAst> {
    if (typeof file.body !== "string") {
      throw new TypeError("File body is not a string");
    }

    try {
      const parsedPkgJson = parsePkg(file.body, file.path);
      const getDependencyPackageJson = createGetDependencyPackageJson({
        pkgDirname: dirname(file.path),
      });

      return {
        ok: true,
        ast: {
          type: "Package",
          parsedPkgJson,
          getDependencyPackageJson,
          loc: { line: 1, column: 1 },
          value: file.body,
          range: [0, file.body.length],
          children: (
            [
              "dependencies",
              "devDependencies",
              "optionalDependencies",
              "peerDependencies",
              "resolutions",
              "resolutionsExplained",
            ] as const
          ).flatMap((dependencyType): DependencyValueAst[] => {
            return Object.values(parsedPkgJson[dependencyType] ?? {}).map(
              (dependencyValue) => {
                return {
                  type: "DependencyValue",
                  dependencyType,
                  parsedPkgJson,
                  getDependencyPackageJson,
                  dependencyValue,
                  loc: dependencyValue!.locations.all.start,
                  range: dependencyValue!.ranges.all,
                  value: dependencyValue!.toString(),
                };
              },
            );
          }),
        },
      };
    } catch (error) {
      return {
        ok: false,
        errors: [
          {
            line: 1,
            column: 1,
            message: error instanceof Error ? error.message : String(error),
          },
        ],
      };
    }
  },

  createSourceCode(
    file: File,
    parseResult: OkParseResult<PackageJsonAst>,
    context: LanguageContext<LanguageOptions>,
  ): PackageJsonSourceCode {
    if (typeof file.body !== "string") {
      throw new TypeError("File body is not a string");
    }

    return new PackageJsonSourceCode({
      text: file.body,
      ast: parseResult.ast,
    });
  },
};
import semver from "semver";
import type { ReportError } from "../reporting/ReportError.ts";
import type {
  DependencyTypes,
  PackageJson,
  ParsedPackageJson,
} from "../utils/packageTypes.ts";
import type { OnlyWarnsForCheck } from "../utils/warnForUtils.ts";

export function checkDuplicateDependencies(
  reportError: ReportError,
  pkg: ParsedPackageJson,
  isPkgLibrary: boolean,
  depType: DependencyTypes,
  searchIn: DependencyTypes[],
  depPkg: PackageJson,
  onlyWarnsForCheck: OnlyWarnsForCheck,
): void {
  const dependencies = depPkg[depType];
  if (!dependencies) return;

  const searchInExisting = searchIn.filter((type) => pkg[type]);

  for (const [depKey, depRange] of Object.entries(dependencies)) {
    const versionsIn = searchInExisting.filter((type) => pkg[type]![depKey]);

    let allowDuplicated = false;
    if (
      versionsIn.length === 2 &&
      isPkgLibrary &&
      versionsIn.includes("dependencies") &&
      versionsIn.includes("devDependencies")
    ) {
      const depVersion = pkg.dependencies![depKey];
      const devDepVersion = pkg.devDependencies![depKey];

      if (depVersion?.value === devDepVersion!.value) {
        reportError({
          errorMessage: `Invalid "${depKey}" has same version in dependencies and devDependencies`,
          errorDetails:
            "please place it only in dependencies or use range in dependencies",
          dependency: depVersion,
        });
        continue;
      }
      allowDuplicated = true;
    }

    if (
      versionsIn.length > 2 ||
      (versionsIn.length === 2 && !allowDuplicated)
    ) {
      reportError({
        errorMessage: `Invalid "${depKey}" present in ${versionsIn.join(" and ")}`,
        errorDetails: "please place it only in dependencies",
      });
    } else {
      const versions = versionsIn.map((type) => pkg[type]![depKey]);

      versions.forEach((version, index) => {
        if (!version) return;
        const versionValue = version.value;
        if (depRange === "latest") return;
        if (versionValue.startsWith("file:") || depRange.startsWith("file:")) {
          return;
        }
        // https://yarnpkg.com/features/workspaces#workspace-ranges-workspace
        if (
          versionValue.startsWith("workspace:") ||
          depRange.startsWith("workspace:")
        ) {
          return;
        }

        // https://yarnpkg.com/features/patching
        if (
          versionValue.startsWith("patch:") ||
          depRange.startsWith("patch:")
        ) {
          return;
        }

        if (
          semver.satisfies(versionValue, depRange, {
            includePrerelease: true,
          }) ||
          semver.intersects(versionValue, depRange, {
            includePrerelease: true,
          })
        ) {
          return;
        }

        // Ignore reporting duplicate when there's a resolution for it
        if (pkg.resolutions?.[depKey]) {
          return;
        }

        const versionInType = versionsIn[index];

        const dependency = versionInType
          ? pkg[versionInType]![depKey]
          : undefined;

        reportError({
          errorMessage: `Invalid duplicate dependency${dependency ? "" : `"${depKey}"`}`,
          errorDetails: `"${versions[0]!.value}" should satisfies "${depRange}" from ${depPkg.name || ""} in ${depType}`,
          onlyWarns: onlyWarnsForCheck.shouldWarnsFor(depKey),
          dependency,
        });
      });
    }
  }
}
import type { DependencyValue, Location } from "../utils/packageTypes.ts";

export interface ReportErrorDetails {
  errorMessage: string;
  errorDetails?: string;
  errorTarget?: "dependencyName" | "dependencyValue";
  dependency?: Omit<Partial<DependencyValue>, "name"> &
    Pick<DependencyValue, "name">;
  onlyWarns?: boolean;
  /** @deprecated use fixTo or suggestTo instead */
  autoFixable?: boolean;
  fixTo?: string;
  suggestions?: [
    dependencyValue: Omit<Partial<DependencyValue>, "name"> &
      Pick<DependencyValue, "name">,
    fixTo: string,
    description: string,
  ][];
}

export type ReportError = (details: ReportErrorDetails) => void;

export type CreateReportError = (
  ruleName: string,
  pkgPathName: string,
) => ReportError;

export const getLocFromDependency = (
  dependency: Partial<DependencyValue>,
  errorTarget: ReportErrorDetails["errorTarget"],
): Location | undefined => {
  if (!dependency.locations) {
    return undefined;
  }

  if (errorTarget === "dependencyName") {
    return dependency.locations.name;
  }
  if (errorTarget === "dependencyValue") {
    return dependency.locations.value;
  }
  return dependency.locations.all;
};
export const getKeys = <T extends object>(o: T): (keyof T)[] =>
  Object.keys(o) as (keyof T)[];

export const getEntries = <T extends object>(o: T): [keyof T, T[keyof T]][] =>
  Object.entries(o) as unknown as [keyof T, T[keyof T]][];
import { getEntries } from "./object.ts";

export type OnlyWarnsFor = string[];
export type OnlyWarnsForDependencyMapping = Record<
  // eslint-disable-next-line @typescript-eslint/no-redundant-type-constituents
  string | "*",
  OnlyWarnsFor | undefined
>;
export type OnlyWarnsForOptionalDependencyMapping =
  | OnlyWarnsFor
  | OnlyWarnsForDependencyMapping
  | undefined;

export interface OnlyWarnsForCheck {
  configName: string;
  getNotWarnedFor: () => string[];
  shouldWarnsFor: (dependencyName: string) => boolean;
}

export interface OnlyWarnsForMappingCheck {
  configName: string;
  getNotWarnedFor: () => Record<string, string[]>;
  createFor: (dependencyName: string) => OnlyWarnsForCheck;
}

export const createOnlyWarnsForArrayCheck = (
  configName: string,
  onlyWarnsFor: OnlyWarnsFor = [],
): OnlyWarnsForCheck => {
  const notWarnedFor = new Set(onlyWarnsFor);
  return {
    configName,
    getNotWarnedFor: () => [...notWarnedFor],
    shouldWarnsFor(dependencyName) {
      if (onlyWarnsFor.includes(dependencyName)) {
        notWarnedFor.delete(dependencyName);
        return true;
      }
      return false;
    },
  };
};

const isMapping = (
  onlyWarnsFor: OnlyWarnsForOptionalDependencyMapping,
): onlyWarnsFor is OnlyWarnsForDependencyMapping => {
  return typeof onlyWarnsFor === "object" && !Array.isArray(onlyWarnsFor);
};

export const createOnlyWarnsForMappingCheck = (
  configName: string,
  onlyWarnsFor: OnlyWarnsForOptionalDependencyMapping,
): OnlyWarnsForMappingCheck => {
  if (isMapping(onlyWarnsFor)) {
    const notWarnedFor = Object.fromEntries(
      getEntries(onlyWarnsFor).map(([entryKey, entryValue]) => [
        entryKey,
        new Set(entryValue),
      ]),
    );
    return {
      configName,
      getNotWarnedFor: () =>
        Object.fromEntries(
          getEntries(notWarnedFor)
            .filter(([key, set]) => set.size > 0)
            .map(([key, set]) => [key, [...set]]),
        ),
      createFor(dependencyNameLevel1) {
        return {
          configName,
          getNotWarnedFor() {
            throw new Error("Invalid call to getNotWarnedFor()");
          },
          shouldWarnsFor(dependencyName) {
            if (onlyWarnsFor["*"]?.includes(dependencyName)) {
              notWarnedFor["*"]?.delete(dependencyName);
              return true;
            }
            if (onlyWarnsFor[dependencyNameLevel1]?.includes(dependencyName)) {
              notWarnedFor[dependencyNameLevel1]?.delete(dependencyName);
              return true;
            }
            return false;
          },
        };
      },
    };
  }

  const arrayOnlyWarnsForCheck = createOnlyWarnsForArrayCheck(
    configName,
    onlyWarnsFor,
  );
  return {
    configName,
    getNotWarnedFor: (): Record<string, string[]> => {
      const notWarnedFor = arrayOnlyWarnsForCheck.getNotWarnedFor();
      if (notWarnedFor.length > 0) {
        return { "*": notWarnedFor };
      }
      return {};
    },
    createFor() {
      return {
        configName,
        getNotWarnedFor() {
          throw new Error("Invalid call to getNotWarnedFor()");
        },
        shouldWarnsFor(dependencyName) {
          return arrayOnlyWarnsForCheck.shouldWarnsFor(dependencyName);
        },
      };
    },
  };
};
import fs, { constants } from "node:fs";
import path from "node:path";
import type { Rule } from "eslint";
import { getLocFromDependency } from "../../reporting/ReportError.ts";
import type {
  ReportError,
  ReportErrorDetails,
} from "../../reporting/ReportError.ts";
import type { GetDependencyPackageJson } from "../../utils/createGetDependencyPackageJson.ts";
import { getEntries } from "../../utils/object.ts";
import type {
  DependencyValue,
  ParsedPackageJson,
} from "../../utils/packageTypes.ts";
import { parsePkg } from "../../utils/pkgJsonUtils.ts";
import type {
  OnlyWarnsFor,
  OnlyWarnsForCheck,
  OnlyWarnsForMappingCheck,
} from "../../utils/warnForUtils.ts";
import {
  createOnlyWarnsForArrayCheck,
  createOnlyWarnsForMappingCheck,
} from "../../utils/warnForUtils.ts";
import type { DependencyValueAst, PackageJsonAst } from "../language.ts";

export const onlyWarnsForArraySchema = {
  type: "array",
  items: { type: "string" },
} as const;
export const onlyWarnsForMappingSchema = {
  type: "object",
  patternProperties: {
    "^.*$": onlyWarnsForArraySchema,
  },
} as const;

// interface CheckPackageDependenciesLanguageOptions {}

interface CheckPackageDependenciesSettings {
  isLibrary?: boolean;
}

type CheckFn<RuleOptions, Node, T = Record<never, never>> = (
  params: T & {
    node: Node;
    pkg: ParsedPackageJson;
    reportError: ReportError;
    // languageOptions: CheckPackageDependenciesLanguageOptions;
    getDependencyPackageJson: GetDependencyPackageJson;
    settings: CheckPackageDependenciesSettings;
    ruleOptions: RuleOptions;
    onlyWarnsForCheck: OnlyWarnsForCheck;
    onlyWarnsForMappingCheck: OnlyWarnsForMappingCheck;
  },
) => void;

export function createPackageRule<
  RuleOptions extends { onlyWarnsFor?: OnlyWarnsFor },
>(
  ruleName: string,
  schema: NonNullable<NonNullable<Rule.RuleModule["meta"]>["schema"]>,
  {
    checkPackage,
    checkDependencyValue,
  }: {
    checkPackage?: CheckFn<
      RuleOptions,
      ParsedPackageJson,
      {
        loadWorkspacePackageJsons: () => ParsedPackageJson[];
        checkOnlyWarnsForArray: (onlyWarnsForCheck: OnlyWarnsForCheck) => void;
        checkOnlyWarnsForMapping: (
          onlyWarnsForMappingCheck: OnlyWarnsForMappingCheck,
        ) => void;
      }
    >;
    checkDependencyValue?: CheckFn<RuleOptions, DependencyValue>;
  },
): Record<string, Rule.RuleModule> {
  return {
    [ruleName]: {
      meta: {
        type: "problem",
        fixable: "code",
        hasSuggestions: true,
        schema: schema ? [schema] : undefined,
      },

      create(context) {
        // const languageOptions =
        //   context.languageOptions as CheckPackageDependenciesLanguageOptions;
        const options = (context.options[0] ?? {}) as RuleOptions;
        const settings = (context.settings["check-package-dependencies"] ??
          {}) as CheckPackageDependenciesSettings;

        const schemaProperties =
          schema && "properties" in schema ? schema.properties : undefined;

        const onlyWarnsForCheck =
          schemaProperties &&
          "onlyWarnsFor" in schemaProperties &&
          schemaProperties.onlyWarnsFor.type === "array" &&
          Array.isArray(options.onlyWarnsFor)
            ? createOnlyWarnsForArrayCheck("onlyWarnsFor", options.onlyWarnsFor)
            : createOnlyWarnsForArrayCheck("onlyWarnsFor", []);

        const onlyWarnsForMappingCheck =
          schemaProperties &&
          "onlyWarnsFor" in schemaProperties &&
          schemaProperties.onlyWarnsFor.type === "object" &&
          typeof options.onlyWarnsFor === "object"
            ? createOnlyWarnsForMappingCheck(
                "onlyWarnsFor",
                options.onlyWarnsFor,
              )
            : createOnlyWarnsForMappingCheck("onlyWarnsFor", {});

        const createReportError =
          (
            fix?: (
              fixer: Rule.RuleFixer,
              details: ReportErrorDetails,
              fixTo: string,
            ) => ReturnType<Rule.ReportFixer>,
          ): ReportError =>
          (details) => {
            const location =
              details.dependency &&
              getLocFromDependency(details.dependency, details.errorTarget);
            const fixTo = details.fixTo;
            const suggestions = details.suggestions;
            const isWarn = details.onlyWarns;
            const dependencyInfo = details.dependency
              ? `${details.dependency.fieldName ? `${details.dependency.fieldName} > ` : ""}${details.dependency.name}: `
              : "";
            const message =
              dependencyInfo +
              details.errorMessage +
              (details.errorDetails ? `: ${details.errorDetails}` : "");
            if (isWarn) {
              console.warn(`[warn] ${message} - ${ruleName}`);
            } else {
              context.report({
                message,

                // TODO improve this by using start+end
                loc: location ?? {
                  start: { line: 1, column: 1 },
                  end: { line: 1, column: 1 },
                },

                fix:
                  fix && fixTo
                    ? (fixer) => fix(fixer, details, fixTo)
                    : undefined,

                suggest:
                  fix && suggestions
                    ? suggestions.map((suggestion) => ({
                        desc: suggestion[2] || `Replace with ${suggestion[1]}`,
                        fix: (fixer) =>
                          fix(
                            fixer,
                            { ...details, dependency: suggestion[0] },
                            suggestion[1],
                          ),
                      }))
                    : undefined,
              });
            }
          };

        const checkOnlyWarnsForArray = (
          onlyWarnsForCheck: OnlyWarnsForCheck,
        ): void => {
          const notWarnedFor = onlyWarnsForCheck.getNotWarnedFor();

          if (notWarnedFor.length > 0) {
            context.report({
              message: `${onlyWarnsForMappingCheck.configName}: no warning was raised for ${notWarnedFor
                .map((depName) => `"${depName}"`)
                .join(", ")}. You should remove it or check if it is correct.`,
              loc: {
                start: { line: 1, column: 1 },
                end: { line: 1, column: 1 },
              },
            });
          }
        };

        const checkOnlyWarnsForMapping = (
          onlyWarnsForMappingCheck: OnlyWarnsForMappingCheck,
        ): void => {
          const notWarnedForMapping =
            onlyWarnsForMappingCheck.getNotWarnedFor();
          getEntries(notWarnedForMapping).forEach(
            ([depNameOrStar, notWarnedFor]) => {
              context.report({
                message: `${onlyWarnsForMappingCheck.configName}: no warning was raised for "${depNameOrStar}" > ${notWarnedFor
                  .map((depName) => `"${depName}"`)
                  .join(", ")}`,
                loc: {
                  start: { line: 1, column: 1 },
                  end: { line: 1, column: 1 },
                },
              });
            },
          );
        };

        return {
          Package(node: any) {
            // Only run on package.json files
            if (!context.filename.endsWith("/package.json")) {
              context.report({
                message: "This rule is only applicable to package.json files",
                loc: {
                  start: { line: 1, column: 1 },
                  end: { line: 1, column: 1 },
                },
              });
            }

            const { parsedPkgJson, getDependencyPackageJson } =
              node as PackageJsonAst;

            const loadWorkspacePackageJsons = (): ParsedPackageJson[] => {
              const workspacePackagesPaths: string[] = [];

              const pkgWorkspaces: string[] | undefined =
                parsedPkgJson.value.workspaces &&
                !Array.isArray(parsedPkgJson.value.workspaces)
                  ? parsedPkgJson.value.workspaces.packages
                  : parsedPkgJson.value.workspaces;

              if (!pkgWorkspaces) {
                throw new Error(
                  "Tried to load workspaces package.json but no workspaces found",
                );
              }

              const dirname = path.dirname(parsedPkgJson.path);

              const match = fs.globSync(pkgWorkspaces, { cwd: dirname });
              for (const pathMatch of match) {
                const subPkgPath = path.relative(process.cwd(), pathMatch);
                const pkgPath = path.join(subPkgPath, "package.json");

                try {
                  fs.accessSync(pkgPath, constants.R_OK);
                } catch {
                  console.log(
                    `Ignored potential directory, no package.json found: ${pathMatch}`,
                  );
                  continue;
                }

                workspacePackagesPaths.push(pkgPath);
              }

              return workspacePackagesPaths.map((path) => {
                try {
                  const body = fs.readFileSync(path, "utf8");
                  const parsedPkgJson = parsePkg(body, path);
                  return parsedPkgJson;
                } catch (error: unknown) {
                  throw new Error(
                    `Failed to read workspace package.json "${path}": ${String(error)}`,
                    { cause: error },
                  );
                }
              });
            };

            try {
              // const checkPackage = createCheckPackage();
              if (checkPackage) {
                checkPackage({
                  node: parsedPkgJson,
                  pkg: parsedPkgJson,
                  getDependencyPackageJson,
                  loadWorkspacePackageJsons,
                  // languageOptions,
                  settings,
                  ruleOptions: options,
                  onlyWarnsForCheck,
                  onlyWarnsForMappingCheck,
                  checkOnlyWarnsForArray,
                  checkOnlyWarnsForMapping,
                  reportError: createReportError(),
                });
              }
            } catch (error: unknown) {
              context.report({
                loc: {
                  start: { line: 1, column: 1 },
                  end: { line: 1, column: 1 },
                },
                message: `Failed to check package dependencies: ${
                  error instanceof Error ? error.message : String(error)
                }`,
              });
            }
          },

          "Package:exit"() {
            try {
              checkOnlyWarnsForArray(onlyWarnsForCheck);
              checkOnlyWarnsForMapping(onlyWarnsForMappingCheck);
            } catch (error: unknown) {
              context.report({
                loc: {
                  start: { line: 1, column: 1 },
                  end: { line: 1, column: 1 },
                },
                message: `Failed to check package dependencies: ${
                  error instanceof Error ? error.message : String(error)
                }`,
              });
            }
          },

          ...(checkDependencyValue
            ? {
                DependencyValue(node: any) {
                  const token = node as DependencyValueAst;
                  const {
                    dependencyValue,
                    parsedPkgJson,
                    getDependencyPackageJson,
                  } = token;
                  if (!dependencyValue) return;
                  checkDependencyValue({
                    node: dependencyValue,
                    pkg: parsedPkgJson,
                    getDependencyPackageJson,
                    // languageOptions,
                    settings,
                    ruleOptions: options,
                    onlyWarnsForCheck,
                    onlyWarnsForMappingCheck,
                    reportError: createReportError((fixer, details, fixTo) => {
                      const targetDependencyValue: Partial<DependencyValue> =
                        details.dependency || dependencyValue;

                      if (details.errorTarget !== "dependencyValue") {
                        throw new Error(
                          `Invalid or unsupported errorTarget: ${String(details.errorTarget)}`,
                        );
                      }

                      targetDependencyValue.changeValue?.(fixTo);

                      if (!targetDependencyValue.ranges) {
                        return null;
                      }

                      const getTargetRangeFromErrorTarget = (
                        errorTarget: ReportErrorDetails["errorTarget"],
                      ): [number, number] | undefined => {
                        switch (errorTarget) {
                          case "dependencyValue":
                            return targetDependencyValue.ranges?.value;
                          case "dependencyName":
                            return targetDependencyValue.ranges?.name;
                          case undefined:
                          default:
                            return targetDependencyValue.ranges?.all;
                        }
                      };

                      const targetRange = getTargetRangeFromErrorTarget(
                        details.errorTarget,
                      );

                      if (!targetRange) {
                        return null;
                      }

                      return fixer.replaceTextRange(
                        targetRange,
                        !details.errorTarget
                          ? dependencyValue.toString()
                          : JSON.stringify(fixTo),
                      );
                    }),
                  });
                },
              }
            : {}),
        };
      },
    } satisfies Rule.RuleModule,
  };
}
import { checkDuplicateDependencies } from "../../checks/checkDuplicateDependencies.ts";
import type {
  DependencyFieldTypes,
  DependencyTypes,
