// eslint-disable-next-line n/no-unsupported-features/node-builtins
import { styleText } from "node:util";
import type { PackageJson } from "type-fest";
import { getEntries } from "../utils/object.ts";
import type { DependencyTypes } from "../utils/packageTypes.ts";
import type {
  OnlyWarnsForCheck,
  OnlyWarnsForMappingCheck,
} from "../utils/warnForUtils.ts";
import { getLocFromDependency } from "./ReportError.ts";
import type { ReportError, ReportErrorDetails } from "./ReportError.ts";

type ReportErrorWithRuleName = ReportErrorDetails & { ruleName: string };

interface ErrorGroup {
  messages: ReportErrorWithRuleName[];
}

const pathMessages = new Map<
  string,
  {
    generalMessages: ReportErrorWithRuleName[];
    dependencyGroups: Map<string, ErrorGroup>;
  }
>();

let totalWarnings = 0;
let totalErrors = 0;
let totalFixable = 0;

function formatErrorMessage({
  errorMessage,
  errorDetails,
  errorTarget,
  onlyWarns,
  // eslint-disable-next-line @typescript-eslint/no-deprecated
  autoFixable,
  fixTo,
  ruleName,
  dependency,
}: ReportErrorWithRuleName): string {
  const location = dependency && getLocFromDependency(dependency, errorTarget);
  const locationString = location
    ? `${location.start.line}:${location.start.column || 0}`
    : "0:0";
  const messageType = onlyWarns
    ? styleText("yellow", "warning")
    : styleText("red", "error");
  const dependencyInfo = dependency
    ? styleText(
        "dim",
        `${dependency.fieldName ? `${dependency.fieldName} > ` : ""}${dependency.name} `,
      )
    : "";
  const details = errorDetails ? `: ${errorDetails}` : "";
  const messageTitle = onlyWarns
    ? styleText("yellow", errorMessage)
    : styleText("red", errorMessage);

  const isFixable = autoFixable || fixTo;
  return `  ${locationString}  ${messageType}  ${dependencyInfo}${messageTitle}${details}  ${styleText("blue", ruleName)}${isFixable ? styleText("dim", " (--fix)") : ""}`;
}

export function logMessage(message: ReportErrorWithRuleName): void {
  if (message.onlyWarns) totalWarnings++;
  else totalErrors++;
  // eslint-disable-next-line @typescript-eslint/no-deprecated
  if (message.autoFixable || message.fixTo) totalFixable++;

  console.error(formatErrorMessage(message));
}

function displayMessagesForPath(
  path: string,
  {
    generalMessages,
    dependencyGroups,
  }: {
    generalMessages: ReportErrorWithRuleName[];
    dependencyGroups: Map<string, ErrorGroup>;
  },
): void {
  console.error(styleText("underline", path));

  // Display general messages first
  if (generalMessages.length > 0) {
    for (const message of generalMessages) {
      logMessage(message);
    }
  }

  // Then display dependency groups
  for (const [, group] of dependencyGroups) {
    for (const message of group.messages) {
      logMessage(message);
    }
  }

  console.error(); // Add empty line between files
}

function displayConclusion(): void {
  if (!totalWarnings && !totalErrors) {
    console.log(styleText("green", "\n✨ No problems found"));
    return;
  }

  const problems = [];
  if (totalErrors) {
    problems.push(
      styleText(
        "red",
        `${totalErrors} ${totalErrors === 1 ? "error" : "errors"}`,
      ),
    );
  }
  if (totalWarnings) {
    problems.push(
      styleText(
        "yellow",
        `${totalWarnings} ${totalWarnings === 1 ? "warning" : "warnings"}`,
      ),
    );
  }

  console.log(`\n✖ Found ${problems.join(" and ")}`);

  if (totalFixable) {
    console.log(
      styleText(
        "dim",
        `\n${totalFixable} ${totalFixable === 1 ? "issue" : "issues"} fixable with the --fix option`,
      ),
    );
  }
}

export function displayMessages(): void {
  // Display all collected messages
  for (const [path, pathData] of pathMessages) {
    displayMessagesForPath(path, pathData);
  }

  displayConclusion();
}

export function createCliReportError(
  ruleName: string,
  pkgPathName: string,
): ReportError {
  return function reportError(message: ReportErrorDetails): void {
    let pathData = pathMessages.get(pkgPathName);
    if (!pathData) {
      pathData = {
        generalMessages: [],
        dependencyGroups: new Map(),
      };
      pathMessages.set(pkgPathName, pathData);
    }

    if (message.dependency) {
      const dependencyKey = `${
        message.dependency.fieldName ? `${message.dependency.fieldName} > ` : ""
      }${message.dependency.name}`;
      let group = pathData.dependencyGroups.get(dependencyKey);
      if (!group) {
        group = { messages: [] };
        pathData.dependencyGroups.set(dependencyKey, group);
      }
      group.messages.push({ ...message, ruleName });
    } else {
      pathData.generalMessages.push({ ...message, ruleName });
    }

    if (!message.onlyWarns) {
      process.exitCode = 1;
    }
  };
}

export function reportNotWarnedFor(
  reportError: ReportError,
  onlyWarnsForCheck: OnlyWarnsForCheck,
): void {
  const notWarnedFor = onlyWarnsForCheck.getNotWarnedFor();
  if (notWarnedFor.length > 0) {
    reportError({
      errorMessage: `Invalid config in "${onlyWarnsForCheck.configName}"`,
      errorDetails: `no warning was raised for ${notWarnedFor
        .map((depName) => `"${depName}"`)
        .join(", ")}`,
    });
  }
}

export function reportNotWarnedForMapping(
  reportError: ReportError,
  onlyWarnsForMappingCheck: OnlyWarnsForMappingCheck,
): void {
  const notWarnedForMapping = onlyWarnsForMappingCheck.getNotWarnedFor();
  getEntries(notWarnedForMapping).forEach(([depNameOrStar, notWarnedFor]) => {
    reportError({
      errorMessage: `Invalid config in "${onlyWarnsForMappingCheck.configName}"`,
      errorDetails: `no warning was raised for ${notWarnedFor
        .map((depName) => `"${depName}"`)
        .join(", ")}`,
    });
  });
}

export function resetMessages(): void {
  pathMessages.clear();
  totalWarnings = 0;
  totalErrors = 0;
  totalFixable = 0;
}

export function fromDependency(
  depPkg: PackageJson,
  depType?: DependencyTypes,
): string {
  return `from "${depPkg.name || ""}"${depType ? ` in "${depType}"` : ""}`;
}

export function inDependency(
  depPkg: PackageJson,
  depType?: DependencyTypes,
): string {
  return `in ${depType ? `"${depType}" of ` : ""}"${depPkg.name || ""}"`;
}
import type { SemVer } from "semver-utils";
import semverUtils from "semver-utils";

export const parse = semverUtils.parse;
export const parseRange = semverUtils.parseRange;

// semverUtils.stringify does not support the operator
function stringify(semver: SemVer): string {
  let str = "";
  if (semver.operator) {
    str += semver.operator;
  }
  str += semver.major || "0";
  str += ".";
  str += semver.minor || "0";
  str += ".";
  str += semver.patch || "0";
  if (semver.release) {
    str += `-${semver.release}`;
  }
  if (semver.build) {
    str += `+${semver.build}`;
  }
  return str;
}

export function getOperator(range: string): string | null {
  const parsedRange = parseRange(range);
  if (parsedRange.length !== 1) return null;
  return parsedRange[0]?.operator || "";
}

export function changeOperator(
  range: string,
  operator: string | null,
): string | null {
  if (operator === null) return range;
  const parsedRange = parseRange(range);
  if (parsedRange.length !== 1) return null;
  const parsed = parsedRange[0];
  if (!parsed) return null;
  parsed.operator = operator === "" ? undefined : operator;
  return stringify(parsed);
}

export function isExactParsedRange(
  parsedRange: ReturnType<typeof semverUtils.parseRange>,
): boolean {
  return parsedRange.length === 1 && parsedRange[0]?.operator === undefined;
}

export function isExactRange(range: string): boolean {
  return isExactParsedRange(parseRange(range));
}

export function getRealVersion(version: string): string {
  if (version.startsWith("npm:")) {
    const match = /^npm:@?[^@]+@(.*)$/.exec(version);
    if (!match) throw new Error(`Invalid version match: ${version}`);
    const [, realVersion] = match;
    if (realVersion) return realVersion;
  }
  if (version.startsWith("workspace:")) {
    return version.slice("workspace:".length);
  }

  return version;
}
import semver from "semver";
import type { ReportError } from "../reporting/ReportError.ts";
import { fromDependency } from "../reporting/cliErrorReporting.ts";
import type {
  DependencyTypes,
  PackageJson,
  ParsedPackageJson,
} from "../utils/packageTypes.ts";
import { getRealVersion } from "../utils/semverUtils.ts";
import type { OnlyWarnsForCheck } from "../utils/warnForUtils.ts";

export function checkSatisfiesPeerDependency(
  reportError: ReportError,
  pkg: ParsedPackageJson,
  type: DependencyTypes,
  allowedPeerIn: DependencyTypes[],
  peerDepName: string,
  range: string,
  depPkg: PackageJson,
  invalidOnlyWarnsForCheck: OnlyWarnsForCheck,
): void {
  const versions = allowedPeerIn.map(
    (versionsInType) => pkg[versionsInType]?.[peerDepName],
  );

  versions.forEach((versionV, index) => {
    if (!versionV) {
      return;
    }
    const version = getRealVersion(versionV.value);

    if (version === "*" || version.startsWith("patch:")) {
      return;
    }

    const minVersionOfVersion = semver.minVersion(version);
    if (
      !minVersionOfVersion ||
      !semver.satisfies(minVersionOfVersion, range, {
        includePrerelease: true,
        loose: true,
      })
    ) {
      reportError({
        errorMessage: "Invalid peer dependency version",
        errorDetails: `"${version}" should satisfies "${range}" ${fromDependency(depPkg, type)}`,
        dependency: allowedPeerIn[index]
          ? (pkg[allowedPeerIn[index]]?.[peerDepName] ?? undefined)
          : undefined,
        onlyWarns: invalidOnlyWarnsForCheck.shouldWarnsFor(peerDepName),
      });
    }
  });
}

export function checkPeerDependencies(
  reportError: ReportError,
  pkg: ParsedPackageJson,
  type: DependencyTypes,
  allowedPeerIn: DependencyTypes[],
  allowMissing: boolean,
  providedDependencies: [
    depName: string,
    depVersion: string,
    depPkgName: string,
  ][],
  depPkg: PackageJson,
  missingOnlyWarnsForCheck: OnlyWarnsForCheck,
  invalidOnlyWarnsForCheck: OnlyWarnsForCheck,
): void {
  const { peerDependencies, peerDependenciesMeta } = depPkg;
  if (!peerDependencies) return;

  const allowedPeerInExisting = allowedPeerIn.filter(
    (allowedPeerInType) => pkg[allowedPeerInType],
  );

  for (const [peerDepName, range] of Object.entries(peerDependencies)) {
    const versionsIn = allowedPeerInExisting.filter(
      (allowedPeerInExistingType) =>
        pkg[allowedPeerInExistingType]?.[peerDepName],
    );
    if (versionsIn.length === 0) {
      if (allowMissing) {
        continue;
      }

      const peerDependenciesMetaPeerDep = peerDependenciesMeta?.[peerDepName];
      if (peerDependenciesMetaPeerDep?.optional) {
        continue;
      }

      let additionalDetails = "";
      // satisfied by another direct dependency
      const providedDependenciesForDepName = providedDependencies.filter(
        ([depName]) => depName === peerDepName,
      );
      if (providedDependenciesForDepName.length > 0) {
        if (
          providedDependenciesForDepName.every(([, depRange]) =>
            semver.intersects(range, depRange),
          )
        ) {
          if (process.env.REPORT_PROVIDED_PEER_DEPENDENCIES) {
            reportError({
              errorMessage: `Missing "${peerDepName}" peer dependency ${fromDependency(depPkg, type)}`,
              errorDetails: `but it is provided by ${providedDependenciesForDepName.map(([depName, depRange, depPkgName]) => depPkgName).join(", ")}`,
              dependency: { name: peerDepName },
              onlyWarns:
                process.env.REPORT_PROVIDED_PEER_DEPENDENCIES === "warn",
            });
          }
          continue;
        }

        additionalDetails +=
          " (required as some dependencies have non-satisfying range too)";
      }

      reportError({
        errorMessage: `Missing "${peerDepName}" peer dependency ${fromDependency(depPkg, type)}`,
        errorDetails: `it should satisfies "${range}" and be in ${allowedPeerIn.join(" or ")}${additionalDetails}`,
        dependency: { name: peerDepName },
        onlyWarns: missingOnlyWarnsForCheck.shouldWarnsFor(peerDepName),
      });
    } else {
      checkSatisfiesPeerDependency(
        reportError,
        pkg,
        type,
        allowedPeerInExisting,
        peerDepName,
        range,
        depPkg,
        invalidOnlyWarnsForCheck,
      );
    }
  }
}
import semver from "semver";
import type { ReportError } from "../reporting/ReportError.ts";
import type { GetDependencyPackageJson } from "../utils/createGetDependencyPackageJson.ts";
import { getKeys } from "../utils/object.ts";
import type {
  DependencyTypes,
  PackageJson,
  ParsedPackageJson,
  RegularDependencyTypes,
} from "../utils/packageTypes.ts";
import type { OnlyWarnsForMappingCheck } from "../utils/warnForUtils.ts";
import { checkPeerDependencies } from "./checkPeerDependencies.ts";

export const regularDependencyTypes: RegularDependencyTypes[] = [
  "devDependencies",
  "dependencies",
  "optionalDependencies",
];

const getAllowedPeerInFromType = (
  depPkgType: RegularDependencyTypes,
  isLibrary: boolean,
): DependencyTypes[] => {
  switch (depPkgType) {
    case "devDependencies":
      return ["devDependencies", "dependencies"];
    case "dependencies":
      return isLibrary
        ? ["dependencies", "peerDependencies"]
        : ["devDependencies", "dependencies"];
    case "optionalDependencies":
      return isLibrary
        ? ["dependencies", "optionalDependencies", "peerDependencies"]
        : ["devDependencies", "dependencies"];

    // no default
  }
};

export function checkDirectPeerDependencies(
  reportError: ReportError,
  isLibrary: boolean,
  pkg: ParsedPackageJson,
  getDependencyPackageJson: GetDependencyPackageJson,
  missingOnlyWarnsForCheck: OnlyWarnsForMappingCheck,
  invalidOnlyWarnsForCheck: OnlyWarnsForMappingCheck,
): void {
  const allDepPkgs: {
    name: string;
    type: RegularDependencyTypes;
    pkg: PackageJson;
    hasDirectMatchingPeerDependency: boolean;
  }[] = [];
  const allDirectDependenciesDependencies: [
    depName: string,
    depVersion: string,
    depPkgName: string,
  ][] = [];

  regularDependencyTypes.forEach((depType) => {
    const dependencies = pkg[depType];
    if (!dependencies) return;
    for (const depName of getKeys(dependencies)) {
      const [depPkg] = getDependencyPackageJson(depName);
      allDepPkgs.push({
        name: depName,
        type: depType,
        pkg: depPkg,
        hasDirectMatchingPeerDependency: pkg.peerDependencies?.[depName]
          ? semver.intersects(
              dependencies[depName]!.value,
              pkg.peerDependencies[depName].value,
            )
          : false,
      });

      if (depPkg.dependencies && !isLibrary) {
        allDirectDependenciesDependencies.push(
          ...Object.entries(depPkg.dependencies).map<[string, string, string]>(
            ([depName, depVersion]) => [depName, depVersion, depPkg.name || ""],
          ),
        );
      }
    }
  });

  for (const {
    name: depName,
    type: depType,
    pkg: depPkg,
    hasDirectMatchingPeerDependency,
  } of allDepPkgs) {
    if (depPkg.peerDependencies) {
      checkPeerDependencies(
        reportError,
        pkg,
        depType,
        getAllowedPeerInFromType(depType, isLibrary),
        hasDirectMatchingPeerDependency,
