        ruleOptions,
        onlyWarnsForCheck,
        getDependencyPackageJson,
      }) => {
        if (!(regularDependencyTypes as string[]).includes(node.fieldName)) {
          return;
        }

        ruleOptions.dependencies.forEach(({ name, from, to }) => {
          const [fromDepName, fromDepIn] =
            typeof from === "string"
              ? [from, "dependencies" as const]
              : [from.name, from.in ?? ("dependencies" as const)];

          if (fromDepName === node.name) {
            const [fromDepPkg] = getDependencyPackageJson(fromDepName);
            const fromDepRange = fromDepPkg[fromDepIn]?.[name];
            if (!fromDepRange) {
              throw new Error(
                `Dependency "${fromDepName}" has no dependency "${name}" in "${fromDepIn}".`,
              );
            }

            const [toDepName, toDepIn] =
              typeof to === "string"
                ? [to, "dependencies" as const]
                : [to.name, to.in ?? ("dependencies" as const)];

            const [toDepPkg] = getDependencyPackageJson(toDepName);
            const toDepRange = toDepPkg[toDepIn]?.[name];
            if (!toDepRange) {
              throw new Error(
                `Dependency "${toDepName}" has no dependency "${name}" in "${toDepIn}".`,
              );
            }

            if (!isVersionSatisfiesRange(fromDepRange, toDepRange)) {
              reportError({
                errorMessage:
                  "Version not satisfied between dependencies for dependency " +
                  `"${name}"`,
                errorDetails: `"${fromDepRange}" from "${fromDepName}" ${fromDepIn} should satisfies "${toDepRange}" from "${toDepName}" ${toDepIn}`,
                onlyWarns: onlyWarnsForCheck.shouldWarnsFor(node.name),
              });
            }
          }
        });
      },
    },
  );
import { regularDependencyTypes } from "../../checks/checkDirectPeerDependencies.ts";
import {
  checkMissingSatisfiesVersions,
  checkSatisfiesVersion,
} from "../../checks/checkSatisfiesVersions.ts";
import { getEntries } from "../../utils/object.ts";
import type { RegularDependencyTypes } from "../../utils/packageTypes.ts";
import type { BaseRuleOptions } from "../create-rule/BaseRuleOptions.ts";
import { createPackageRule } from "../create-rule/createPackageRule.ts";

interface CheckSatisfiesVersionsFromDependenciesOptions extends BaseRuleOptions {
  dependencies: Record<
    string,
    Partial<Record<RegularDependencyTypes, string[]>>
  >;
}

export const satisfiesVersionsFromDependenciesRule =
  createPackageRule<CheckSatisfiesVersionsFromDependenciesOptions>(
    "satisfies-versions-from-dependencies",
    {
      type: "object",
      properties: {
        dependencies: {
          type: "object",
          patternProperties: {
            ".*": {
              type: "object",
              properties: {
                dependencies: {
                  type: "array",
                  items: { type: "string" },
                  optional: true,
                },
                devDependencies: {
                  type: "array",
                  items: { type: "string" },
                  optional: true,
                },
                optionalDependencies: {
                  type: "array",
                  items: { type: "string" },
                  optional: true,
                },
              },
              additionalProperties: false,
            },
          },
          additionalProperties: false,
        },
      },
      required: ["dependencies"],
      additionalProperties: false,
    },
    {
      checkPackage: ({
        pkg,
        reportError,
        ruleOptions,
        getDependencyPackageJson,
        onlyWarnsForCheck,
      }) => {
        if (!ruleOptions.dependencies) {
          throw new Error(
            'Rule "check-package-dependencies/satisfies-versions-from-dependencies" is enabled but no dependencies are configured to check',
          );
        }

        Object.entries(ruleOptions.dependencies).forEach(
          ([depName, values]) => {
            const [depPkg] = getDependencyPackageJson(depName);

            regularDependencyTypes.forEach((type) => {
              if (values[type]) {
                const dependenciesRanges = Object.fromEntries(
                  values[type].map((v) => {
                    const range = depPkg.dependencies?.[v];
                    if (!range) {
                      throw new Error(
                        `Dependency ${depName} has no dependency ${v} in ${type}`,
                      );
                    }
                    return [v, range];
                  }),
                );

                checkMissingSatisfiesVersions(
                  reportError,
                  pkg,
                  type,
                  dependenciesRanges,
                  onlyWarnsForCheck,
                );
              }
            });
          },
        );
      },
      checkDependencyValue: ({
        node,
        reportError,
        ruleOptions,
        onlyWarnsForCheck,
        getDependencyPackageJson,
      }) => {
        if (!(regularDependencyTypes as string[]).includes(node.fieldName)) {
          return;
        }
        const fieldName = node.fieldName as RegularDependencyTypes;

        getEntries(ruleOptions.dependencies).forEach(([depName, values]) => {
          if (values[fieldName]?.includes(node.name)) {
            const [depPkg] = getDependencyPackageJson(depName);
            const range = depPkg.dependencies?.[node.name];
            if (!range) {
              throw new Error(
                `Dependency "${depName}" has no dependency "${fieldName}"`,
              );
            }
            checkSatisfiesVersion(reportError, node, range, onlyWarnsForCheck);
          }
        });
      },
    },
  );
import { regularDependencyTypes } from "../../checks/checkDirectPeerDependencies.ts";
import { checkDuplicateDependencies } from "../../checks/checkDuplicateDependencies.ts";
import { checkSatisfiesPeerDependency } from "../../checks/checkPeerDependencies.ts";
import type { ReportError } from "../../reporting/ReportError.ts";
import { getKeys } from "../../utils/object.ts";
import type {
  DependencyFieldTypes,
  DependencyTypes,
  PackageJson,
  ParsedPackageJson,
  RegularDependencyTypes,
} from "../../utils/packageTypes.ts";
import type { OnlyWarnsForCheck } from "../../utils/warnForUtils.ts";
import { createPackageRule } from "../create-rule/createPackageRule.ts";

const duplicatesSearchInByDependencyType: Partial<
  Record<DependencyFieldTypes, DependencyTypes[]>
> = {
  devDependencies: ["devDependencies", "dependencies"],
  dependencies: ["devDependencies", "dependencies"],
  peerDependencies: ["peerDependencies"],
};

const checkDuplicateInAllDependencies = (
  reportError: ReportError,
  basePkg: ParsedPackageJson,
  subPkg: ParsedPackageJson,
  isPkgLibrary: boolean,
  onlyWarnsForCheck: OnlyWarnsForCheck,
): void => {
  (["devDependencies", "dependencies"] as const).forEach((depType) => {
    const dependencies = basePkg[depType];
    if (!dependencies || !duplicatesSearchInByDependencyType[depType]) return;

    checkDuplicateDependencies(
      ({ dependency, errorMessage, ...otherDetails }) => {
        // hide dependency from error details as it is the dependency of the sub package and we are in the context of the root package
        reportError({
          ...otherDetails,
          errorMessage: `${subPkg.name}: ${errorMessage}`,
        });
      },
      subPkg,
      isPkgLibrary,
      depType,
      duplicatesSearchInByDependencyType[depType],
      basePkg.value,
      onlyWarnsForCheck,
    );
  });
};

// TODO this rule is currently very limited in the way errors are reported. It should be improved.
export const workspaceDependenciesRule = createPackageRule(
  "workspace-dependencies",
  {
    type: "object",
    properties: {},
    additionalProperties: false,
  },
  {
    checkPackage: ({
      pkg,
      settings,
      reportError,
      loadWorkspacePackageJsons,
      getDependencyPackageJson,
      onlyWarnsForMappingCheck,
    }) => {
      if (!pkg.value.workspaces) {
        return;
      }

      const workspacePackageJsons = loadWorkspacePackageJsons();

      const previousCheckedWorkspaces: ParsedPackageJson[] = [];

      for (const subPkg of workspacePackageJsons) {
        const onlyWarnsForCheck = onlyWarnsForMappingCheck.createFor(
          subPkg.name,
        );

        // root
        checkDuplicateInAllDependencies(
          reportError,
          pkg,
          subPkg,
          settings.isLibrary ?? false,
          onlyWarnsForCheck,
        );

        // previous packages
        previousCheckedWorkspaces.forEach((previousSubPkg) => {
          checkDuplicateInAllDependencies(
            reportError,
            previousSubPkg,
            subPkg,
            settings.isLibrary ?? false,
            onlyWarnsForCheck,
          );
        });

        // add to previous checked workspaces
        previousCheckedWorkspaces.push(subPkg);

        // peer dependencies via monorepo that is not present in the sub package
        const allDepPkgs: {
          name: string;
          type: RegularDependencyTypes;
          pkg: PackageJson;
        }[] = [];

        regularDependencyTypes.forEach((depType) => {
          const dependencies = subPkg[depType];
          if (!dependencies) return;
          for (const depName of getKeys(dependencies)) {
            const [depPkg] = getDependencyPackageJson(depName);
            if (pkg.devDependencies?.[depName]) {
              continue; // we already checked this.
            }
            allDepPkgs.push({ name: depName, type: depType, pkg: depPkg });
          }
        });

        for (const {
          name: depName,
          type: depType,
          pkg: depPkg,
        } of allDepPkgs) {
          if (depPkg.peerDependencies) {
            for (const [peerDepName, range] of Object.entries(
              depPkg.peerDependencies,
            )) {
              if (subPkg.devDependencies?.[peerDepName]) {
                continue; // skip as already checked in checkDirectPeerDependencies for the subpackage itself.
              }
              checkSatisfiesPeerDependency(
                reportError,
                pkg,
                depType,
                ["devDependencies"],
                peerDepName,
                range,
                depPkg,
                onlyWarnsForMappingCheck.createFor(
                  `${depName}:peedDepdencies:invalid`,
                ),
              );
            }
          }
        }
      }
    },
  },
);
import { directDuplicateDependenciesRule } from "./rules/direct-duplicate-dependencies.ts";
import { directPeerDependenciesRule } from "./rules/direct-peer-dependencies.ts";
import { exactVersionsRule } from "./rules/exact-versions.ts";
import { minRangeDependenciesSatisfiesDevDependenciesRule } from "./rules/min-range-dependencies-satisfies-dev-dependencies.ts";
import { minRangePeerDependenciesSatisfiesDependenciesRule } from "./rules/min-range-peer-dependencies-satisfies-dependencies.ts";
import { resolutionsHasExplanationRule } from "./rules/resolutions-has-explanation.ts";
import { resolutionsVersionsMatchRule } from "./rules/resolutions-versions-match.ts";
import { rootWorkspaceShouldNotHaveDependenciesRule } from "./rules/root-workspace-should-not-have-dependencies.ts";
import { satisfiesVersionsRule } from "./rules/satisfies-version.ts";
import { satisfiesVersionsBetweenDependenciesRule } from "./rules/satisfies-versions-between-dependencies.ts";
import { satisfiesVersionsFromDependenciesRule } from "./rules/satisfies-versions-from-dependencies.ts";
import { workspaceDependenciesRule } from "./rules/workspace-dependencies.ts";

const rules = {
  ...directPeerDependenciesRule,
  ...directDuplicateDependenciesRule,
  ...exactVersionsRule,
  ...minRangeDependenciesSatisfiesDevDependenciesRule,
  ...minRangePeerDependenciesSatisfiesDependenciesRule,
  ...resolutionsVersionsMatchRule,
  ...satisfiesVersionsRule,
  ...resolutionsHasExplanationRule,
  ...rootWorkspaceShouldNotHaveDependenciesRule,
  ...satisfiesVersionsFromDependenciesRule,
  ...satisfiesVersionsBetweenDependenciesRule,
  ...workspaceDependenciesRule,
};

export default rules;
